  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→import { LABEL_Z_MAX } from '../hooks/useRocketMode';
  4→
  5→const TWO_PI = Math.PI * 2;
  6→const SPEED_LINE_COUNT = 30;
  7→
  8→const RocketLayer = React.memo(({ rocketMode }) => {
  9→    const {
 10→        layerRef, starsRef, sortedIndicesRef, velocity, targetIndexRef,
 11→        stageSizeRef, project, getSpeedRatio,
 12→        dockingStateRef, dockingTargetIdxRef, dockingProgressRef, dockingStarScaleRef,
 13→    } = rocketMode;
 14→
 15→    const shapeRef = useRef(null);
 16→    const timeRef = useRef(0);
 17→
 18→    // Attach the Konva Layer ref so the hook can call batchDraw
 19→    const layerCallbackRef = useCallback((node) => {
 20→        layerRef.current = node;
 21→    }, [layerRef]);
 22→
 23→    // Keep time ticking for pulsing effects
 24→    useEffect(() => {
 25→        const update = () => {
 26→            timeRef.current = performance.now();
 27→        };
 28→        const id = setInterval(update, 16);
 29→        return () => clearInterval(id);
 30→    }, []);
 31→
 32→    return (
 33→        <Layer ref={layerCallbackRef} listening={false}>
 34→            <Shape
 35→                ref={shapeRef}
 36→                sceneFunc={(ctx) => {
 37→                    const size = stageSizeRef.current;
 38→                    const cx = size.width / 2;
 39→                    const cy = size.height / 2;
 40→                    const stars = starsRef.current;
 41→                    const sorted = sortedIndicesRef.current;
 42→                    const speedRatio = getSpeedRatio();
 43→                    const time = timeRef.current || performance.now();
 44→                    const targetIdx = targetIndexRef.current;
 45→                    const bufferX = size.width / 2 + 200;
 46→                    const bufferY = size.height / 2 + 200;
 47→                    const focalLength = size.width * 0.6;
 48→
 49→                    // Read docking state
 50→                    const dockState = dockingStateRef.current;
 51→                    const dockTargetIdx = dockingTargetIdxRef.current;
 52→                    const dockProgress = dockingProgressRef.current;
 53→                    const dockStarScale = dockingStarScaleRef.current;
 54→                    const dockingActive = dockState !== 'none';
 55→
 56→                    // ── 1. Speed lines — converging streaks toward center ─
 57→                    if (speedRatio > 0.4) {
 58→                        const lineAlpha = (speedRatio - 0.4) / 0.6;
 59→                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
 60→                        ctx.lineWidth = 1;
 61→
 62→                        for (let i = 0; i < SPEED_LINE_COUNT; i++) {
 63→                            const angle = (i / SPEED_LINE_COUNT) * TWO_PI;
 64→                            const outerR = 200 + speedRatio * 300 + Math.sin(time * 0.002 + i) * 20;
 65→                            const innerR = 40 + speedRatio * 60;
 66→                            ctx.beginPath();
 67→                            ctx.moveTo(
 68→                                cx + Math.cos(angle) * outerR,
 69→                                cy + Math.sin(angle) * outerR
 70→                            );
 71→                            ctx.lineTo(
 72→                                cx + Math.cos(angle) * innerR,
 73→                                cy + Math.sin(angle) * innerR
 74→                            );
 75→                            ctx.stroke();
 76→                        }
 77→                    }
 78→
 79→                    // ── 2. Stars (painter's algorithm, far first) ────────
 80→                    for (let si = 0; si < sorted.length; si++) {
 81→                        const idx = sorted[si];
 82→                        const star = stars[idx];
 83→                        const projected = project(star, cx, cy);
 84→
 85→                        // Null guard — star is behind camera
 86→                        if (!projected) continue;
 87→
 88→                        const { projX, projY, scale } = projected;
 89→
 90→                        // Viewport cull
 91→                        if (projX < cx - bufferX || projX > cx + bufferX ||
 92→                            projY < cy - bufferY || projY > cy + bufferY) continue;
 93→
 94→                        const baseRadius = star.radius * scale * 0.08;
 95→                        if (baseRadius < 0.3) continue;
 96→
 97→                        const stretchX = 1 + speedRatio * 2.5;
 98→                        const opacity = Math.max(0.1, 1 - speedRatio * 0.6);
 99→                        let drawR = Math.min(baseRadius, 60);
100→                        const { r, g, b } = star.colorRgb;
101→
102→                        // ── Docking star scale-up ─────────────────────
103→                        if (dockingActive && idx === dockTargetIdx) {
104→                            drawR = Math.min(drawR * dockStarScale, 300);
105→                        }
106→
107→                        ctx.save();
108→                        ctx.translate(projX, projY);
109→                        ctx.scale(stretchX, 1);
110→
111→                        // Outer glow
112→                        const glowR = drawR * 2.5;
113→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, glowR);
114→                        grad.addColorStop(0, `rgba(${r},${g},${b},${opacity * 0.5})`);
115→                        grad.addColorStop(0.4, `rgba(${r},${g},${b},${opacity * 0.15})`);
116→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
117→                        ctx.beginPath();
118→                        ctx.arc(0, 0, glowR, 0, TWO_PI);
119→                        ctx.fillStyle = grad;
120→                        ctx.fill();
121→
122→                        // Core (white-hot center)
123→                        const coreR = drawR * 0.4;
124→                        ctx.beginPath();
125→                        ctx.arc(0, 0, Math.max(coreR, 0.5), 0, TWO_PI);
126→                        ctx.fillStyle = `rgba(255,255,255,${opacity * 0.9})`;
127→                        ctx.fill();
128→
129→                        ctx.restore();
130→
131→                        // ── Dynamic label (when close) ───────────────────
132→                        const viewZ = star.viewZ;
133→                        if (viewZ > 0 && viewZ < LABEL_Z_MAX) {
134→                            const labelOpacity = (1 - viewZ / LABEL_Z_MAX) * (1 - speedRatio * 0.8);
135→                            if (labelOpacity > 0.05) {
136→                                const rawFontSize = focalLength * star.radius / viewZ * 0.015;
137→                                const fontSize = Math.max(10, Math.min(18, rawFontSize));
138→                                const labelY = projY + drawR * stretchX * 1.8 + fontSize;
139→
140→                                // Title
141→                                ctx.font = `bold ${fontSize}px sans-serif`;
142→                                ctx.fillStyle = `rgba(255,255,255,${labelOpacity * 0.9})`;
143→                                ctx.textAlign = 'center';
144→                                ctx.fillText(star.title, projX, labelY);
145→
146→                                // Author (smaller, blue-tinted)
147→                                const authorSize = Math.max(9, fontSize * 0.75);
148→                                ctx.font = `${authorSize}px sans-serif`;
149→                                ctx.fillStyle = `rgba(140,180,255,${labelOpacity * 0.7})`;
150→                                ctx.fillText(star.authorName, projX, labelY + authorSize + 2);
151→                            }
152→                        }
153→
154→                        // ── 3. Targeting bracket (enhanced) ───────────────
155→                        if (idx === targetIdx) {
156→                            const pulse = 0.6 + 0.4 * Math.sin(time * 0.004);
157→
158→                            // Color transition based on distance
159→                            let bracketR, bracketG, bracketB;
160→                            if (viewZ > 100) {
161→                                // Cyan
162→                                bracketR = 0; bracketG = 255; bracketB = 255;
163→                            } else if (viewZ > 40) {
164→                                // Cyan → orange interpolation
165→                                const t = (100 - viewZ) / 60;
166→                                bracketR = Math.round(0 + t * 255);
167→                                bracketG = Math.round(255 - t * 90);
168→                                bracketB = Math.round(255 - t * 205);
169→                            } else {
170→                                // Orange → red interpolation
171→                                const t = Math.max(0, (40 - viewZ) / 40);
172→                                bracketR = 255;
173→                                bracketG = Math.round(165 - t * 165);
174→                                bracketB = Math.round(50 - t * 50);
175→                            }
176→
177→                            // Growing bracket based on proximity
178→                            const closeFactor = Math.max(0, 1 - viewZ / 200);
179→                            const sizeMultiplier = 1 + closeFactor * 2.5;
180→                            const bracketSize = Math.max(drawR * stretchX * 4, 18) * sizeMultiplier;
181→                            const half = bracketSize / 2;
182→                            const arm = bracketSize * 0.35;
183→
184→                            ctx.strokeStyle = `rgba(${bracketR},${bracketG},${bracketB},${pulse})`;
185→                            ctx.lineWidth = 1.5 + closeFactor * 1;
186→                            ctx.setLineDash([3, 3]);
187→
188→                            // Top-left
189→                            ctx.beginPath();
190→                            ctx.moveTo(projX - half, projY - half + arm);
191→                            ctx.lineTo(projX - half, projY - half);
192→                            ctx.lineTo(projX - half + arm, projY - half);
193→                            ctx.stroke();
194→
195→                            // Top-right
196→                            ctx.beginPath();
197→                            ctx.moveTo(projX + half - arm, projY - half);
198→                            ctx.lineTo(projX + half, projY - half);
199→                            ctx.lineTo(projX + half, projY - half + arm);
200→                            ctx.stroke();
201→
202→                            // Bottom-right
203→                            ctx.beginPath();
204→                            ctx.moveTo(projX + half, projY + half - arm);
205→                            ctx.lineTo(projX + half, projY + half);
206→                            ctx.lineTo(projX + half - arm, projY + half);
207→                            ctx.stroke();
208→
209→                            // Bottom-left
210→                            ctx.beginPath();
211→                            ctx.moveTo(projX - half + arm, projY + half);
212→                            ctx.lineTo(projX - half, projY + half);
213→                            ctx.lineTo(projX - half, projY + half - arm);
214→                            ctx.stroke();
215→
216→                            ctx.setLineDash([]);
217→
218→                            // Distance readout (top-right of bracket)
219→                            const distanceLY = Math.round(viewZ * 7);
220→                            ctx.font = '11px monospace';
221→                            ctx.fillStyle = `rgba(${bracketR},${bracketG},${bracketB},${pulse * 0.9})`;
222→                            ctx.textAlign = 'left';
223→                            ctx.fillText(`${distanceLY} LY`, projX + half + 6, projY - half + 12);
224→                        }
225→                    }
226→
227→                    // ── 4. Canvas flash overlay (Phase 3 only: progress > 0.9) ──
228→                    if (dockProgress > 0.9) {
229→                        const flashAlpha = (dockProgress - 0.9) / 0.1;
230→                        const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, Math.max(size.width, size.height) * 0.7);
231→                        grad.addColorStop(0, `rgba(255,255,255,${flashAlpha})`);
232→                        grad.addColorStop(0.6, `rgba(200,220,255,${flashAlpha * 0.7})`);
233→                        grad.addColorStop(1, `rgba(100,150,255,${flashAlpha * 0.3})`);
234→                        ctx.fillStyle = grad;
235→                        ctx.fillRect(0, 0, size.width, size.height);
236→                    }
237→                }}
238→                perfectDrawEnabled={false}
239→                listening={false}
240→            />
241→        </Layer>
242→    );
243→});
244→
245→RocketLayer.displayName = 'RocketLayer';
246→
247→export default RocketLayer;
