 209→
 210→    const getComputedStarPosition = useCallback((post) => {
 211→        if (!post) return null;
 212→
 213→        const uid = post.users?.id ?? post.user_id;
 214→        const hashGal = userHomeCoords(uid);
 215→        const animGal = galaxyPositions.get(uid);
 216→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 217→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 218→        const pull = starPullOffsets.get(post.id);
 219→
 220→        const baseX = post.universe_x ?? post.display_x;
 221→        const baseY = post.universe_y ?? post.display_y;
 222→        if (baseX == null || baseY == null) return null;
 223→
 224→        return {
 225→            x: baseX + galDx + (pull?.dx ?? 0),
 226→            y: baseY + galDy + (pull?.dy ?? 0),
 227→        };
 228→    }, [galaxyPositions, starPullOffsets]);
 229→
 230→    // ── Hoisted computedStarPositions for sharing across layers ──────
 231→    const computedStarPositions = useMemo(() => {
 232→        const map = new Map();
 233→        for (const post of postArray) {
 234→            const uid = post.users?.id ?? post.user_id;
 235→            const hashGal = userHomeCoords(uid);
 236→            const animGal = galaxyPositions.get(uid);
 237→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 238→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 239→            const pull = starPullOffsets.get(post.id);
 240→
 241→            const baseX = post.universe_x ?? post.display_x;
 242→            const baseY = post.universe_y ?? post.display_y;
 243→            if (baseX == null || baseY == null) continue;
 244→
 245→            let x = baseX + galDx + (pull?.dx ?? 0);
 246→            let y = baseY + galDy + (pull?.dy ?? 0);
 247→
 248→            map.set(post.id, { x, y });
 249→        }
 250→        return map;
 251→    }, [postArray, galaxyPositions, starPullOffsets]);
 252→
 253→    // ── Constellation pull offsets (spring constraint) ─────────────
 254→    const acceptedConstellations = useMemo(
 255→        () => constellations.filter(c => c.status === 'accepted'),
 256→        [constellations]
 257→    );
